/**
 * Code Fix Proposal Framework
 * 
 * Provides structured interfaces for representing automated code fixes
 * generated from governance violations with risk-based stratification.
 */

export interface CodeFixProposal {
  /** Unique identifier for the proposal */
  proposalId: string;
  
  /** Associated pattern that triggered this fix */
  pattern: string;
  
  /** ID of the governance violation */
  violationId?: string;
  
  /** Target file path (absolute or relative to repo root) */
  filePath?: string;
  
  /** Proposed code snippet or fix content */
  codeSnippet?: string;
  
  /** Human-readable description of the fix */
  description: string;
  
  /** Risk level: low, medium, high */
  riskLevel: 'low' | 'medium' | 'high';
  
  /** Whether manual approval is required */
  approvalRequired: boolean;
  
  /** Execution mode: apply (auto), dry-run (preview), manual (user action) */
  mode: 'apply' | 'dry-run' | 'manual';
  
  /** Rationale explaining why this fix is needed */
  rationale: string;
  
  /** Impact assessment */
  impact?: {
    /** Estimated lines of code affected */
    locAffected?: number;
    /** Modules or components affected */
    modulesAffected?: string[];
    /** Test coverage impact */
    testCoverageImpact?: 'increase' | 'decrease' | 'neutral';
  };
  
  /** Economic metrics */
  economic?: {
    /** Cost of delay if not fixed */
    cod?: number;
    /** WSJF priority score */
    wsjfScore?: number;
    /** Time to apply (minutes) */
    timeToApply?: number;
  };
  
  /** Metadata */
  metadata?: {
    /** Who/what generated this proposal */
    generatedBy?: 'governance-agent' | 'retro-coach' | 'manual';
    /** Timestamp of proposal creation */
    createdAt?: string;
    /** Associated action ID from Goalie board */
    actionId?: string;
    /** Tags for categorization */
    tags?: string[];
  };
  
  /** Validation rules */
  validation?: {
    /** Pre-conditions that must be met */
    preconditions?: string[];
    /** Post-conditions to verify after application */
    postconditions?: string[];
    /** Required tests to pass */
    requiredTests?: string[];
  };
}

export interface CodeFixProposalBatch {
  /** Batch identifier */
  batchId: string;
  
  /** Proposals in this batch */
  proposals: CodeFixProposal[];
  
  /** Batch-level risk assessment */
  overallRiskLevel: 'low' | 'medium' | 'high';
  
  /** Whether entire batch requires approval */
  batchApprovalRequired: boolean;
  
  /** Execution strategy: sequential, parallel, or staged */
  executionStrategy: 'sequential' | 'parallel' | 'staged';
  
  /** Dependencies between proposals */
  dependencies?: Array<{
    proposalId: string;
    dependsOn: string[];
  }>;
}

export interface CodeFixApplicationResult {
  /** ID of the applied proposal */
  proposalId: string;
  
  /** Success or failure */
  success: boolean;
  
  /** Error message if failed */
  error?: string;
  
  /** Files actually modified */
  filesModified?: string[];
  
  /** Test results if tests were run */
  testResults?: {
    passed: number;
    failed: number;
    skipped: number;
  };
  
  /** Duration in milliseconds */
  durationMs?: number;
  
  /** Timestamp of application */
  appliedAt?: string;
}

/**
 * Risk stratification rules for code fix proposals
 */
export const RiskStratificationRules = {
  /**
   * Determine risk level based on file path and pattern
   */
  assessRisk(filePath: string | undefined, pattern: string, snippet: string | undefined): 'low' | 'medium' | 'high' {
    // High risk: core infrastructure, auth, security, database
    if (filePath) {
      if (
        filePath.includes('/auth/') ||
        filePath.includes('/security/') ||
        filePath.includes('/database/') ||
        filePath.includes('/core/') ||
        filePath.includes('migration') ||
        filePath.match(/\.sql$/) ||
        filePath.includes('/api/') && pattern.includes('security')
      ) {
        return 'high';
      }
      
      // Medium risk: API endpoints, business logic, config
      if (
        filePath.includes('/api/') ||
        filePath.includes('/config/') ||
        filePath.includes('/services/') ||
        filePath.match(/\.(yaml|yml|json)$/)
      ) {
        return 'medium';
      }
    }
    
    // High risk patterns
    if (
      pattern.includes('security') ||
      pattern.includes('auth') ||
      pattern.includes('permission') ||
      pattern.includes('sql-injection') ||
      pattern.includes('xss')
    ) {
      return 'high';
    }
    
    // Medium risk patterns
    if (
      pattern.includes('api-') ||
      pattern.includes('data-') ||
      pattern.includes('state-management')
    ) {
      return 'medium';
    }
    
    // Check snippet content for risky operations
    if (snippet) {
      if (
        snippet.includes('DROP TABLE') ||
        snippet.includes('DELETE FROM') ||
        snippet.includes('TRUNCATE') ||
        snippet.includes('rm -rf') ||
        snippet.includes('eval(') ||
        snippet.includes('exec(')
      ) {
        return 'high';
      }
    }
    
    // Low risk by default: tests, docs, styles, observability
    return 'low';
  },
  
  /**
   * Determine if approval is required based on risk and mode
   */
  requiresApproval(riskLevel: 'low' | 'medium' | 'high', autoCommitEnabled: boolean): boolean {
    if (riskLevel === 'high') return true;
    if (riskLevel === 'medium' && !autoCommitEnabled) return true;
    return false;
  },
  
  /**
   * Determine execution mode based on risk and policy
   */
  determineMode(
    riskLevel: 'low' | 'medium' | 'high',
    autoCommitEnabled: boolean,
    dryRunOnly: boolean
  ): 'apply' | 'dry-run' | 'manual' {
    if (dryRunOnly) return 'dry-run';
    if (riskLevel === 'high') return 'manual';
    if (riskLevel === 'medium') {
      return autoCommitEnabled ? 'apply' : 'dry-run';
    }
    return autoCommitEnabled ? 'apply' : 'dry-run';
  }
};

/**
 * Factory for creating code fix proposals from governance violations
 */
export class CodeFixProposalFactory {
  constructor(
    private readonly goalieDir: string,
    private readonly autoCommitEnabled: boolean = false,
    private readonly dryRunOnly: boolean = false
  ) {}
  
  /**
   * Create a proposal from a governance pattern violation
   */
  createFromPattern(
    pattern: string,
    description: string,
    options: {
      filePath?: string;
      codeSnippet?: string;
      rationale?: string;
      violationId?: string;
      actionId?: string;
      tags?: string[];
    } = {}
  ): CodeFixProposal {
    const proposalId = `fix-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const riskLevel = RiskStratificationRules.assessRisk(options.filePath, pattern, options.codeSnippet);
    const approvalRequired = RiskStratificationRules.requiresApproval(riskLevel, this.autoCommitEnabled);
    const mode = RiskStratificationRules.determineMode(riskLevel, this.autoCommitEnabled, this.dryRunOnly);
    
    return {
      proposalId,
      pattern,
      violationId: options.violationId,
      filePath: options.filePath,
      codeSnippet: options.codeSnippet,
      description,
      riskLevel,
      approvalRequired,
      mode,
      rationale: options.rationale || `Auto-generated fix for pattern: ${pattern}`,
      metadata: {
        generatedBy: 'governance-agent',
        createdAt: new Date().toISOString(),
        actionId: options.actionId,
        tags: options.tags || [pattern],
      },
    };
  }
  
  /**
   * Create a batch of related proposals
   */
  createBatch(proposals: CodeFixProposal[], executionStrategy: 'sequential' | 'parallel' | 'staged' = 'sequential'): CodeFixProposalBatch {
    const batchId = `batch-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const highRiskCount = proposals.filter(p => p.riskLevel === 'high').length;
    const mediumRiskCount = proposals.filter(p => p.riskLevel === 'medium').length;
    
    const overallRiskLevel: 'low' | 'medium' | 'high' = 
      highRiskCount > 0 ? 'high' :
      mediumRiskCount > 0 ? 'medium' :
      'low';
    
    const batchApprovalRequired = proposals.some(p => p.approvalRequired);
    
    return {
      batchId,
      proposals,
      overallRiskLevel,
      batchApprovalRequired,
      executionStrategy,
    };
  }
}
